async function main() {
  // Re-validate at runtime — never insert a case that fails the depth gate.
  for (const c of CASES) {
    const v = validateExamDepth(c);
    if (!v.ok) { console.error('REFUSING to insert "' + c.title + '":\n  ' + v.errors.join('\n  ')); process.exit(1); }
  }
  if (!process.env.MONGO_URI) { console.error('MONGO_URI is not set.'); process.exit(1); }
  await mongoose.connect(process.env.MONGO_URI, { dbName: 'passreadyprep' });
  const exam = await Exam.findOne({ key: 'ncmhce' });
  if (!exam) { console.error('No ncmhce exam found.'); process.exit(1); }

  const existing = await ContentItem.find({ examId: exam._id, format: 'case_sim' }).select('externalId status caseSim').lean();
  const live = existing.filter((d) => d.status !== 'draft' && d.caseSim).map((d) => d.caseSim);

  // One shared, batch-aware allocator: reserves DB ids + every D-id hardcoded in
  // the batch files, so these land above the whole D101–D189 range (D190/D191)
  // instead of clobbering an unimported batch case (e.g. D168 = Substance).
  const ids = idAllocator.allocate(existing.map((d) => d.externalId), CASES.length, { prefix: 'D' });

  const plan = [];
  CASES.forEach((c, i) => {
    const near = dedup.isNearDuplicate(c, live, { threshold: 0.55 });
    if (near.dup) console.log('NOTE: "' + c.title + '" looks similar to an existing case — inserting anyway (requested).');
    plan.push({ id: ids[i], c }); live.push(c);
  });

  console.log('\nWould insert ' + plan.length + ' case(s) as "' + STATUS + '":');
  plan.forEach((p) => console.log('  ' + p.id + '  [' + p.c.category + ']  ' + p.c.title));
  if (!APPLY) { console.log('\nDRY RUN. Re-run with --apply (add --publish to go straight to live).'); await mongoose.disconnect(); return; }

  for (const p of plan) {
    const c = p.c;
    await ContentItem.create({
      examId: exam._id, format: 'case_sim', externalId: p.id,
      title: c.title, category: c.category, difficulty: c.difficulty,
      references: c.references || [], status: STATUS,
      caseSim: Object.assign({}, c, { id: p.id }),
    });
    console.log('  INSERT ' + p.id + '  ' + c.title);
  }
  const pend = await ContentItem.countDocuments({ examId: exam._id, status: 'sme_review' });
  const pub = await ContentItem.countDocuments({ examId: exam._id, status: 'published' });
  console.log('\nInserted ' + plan.length + ' as ' + STATUS + '. Now sme_review: ' + pend + ', published: ' + pub + '.');
  await mongoose.disconnect();
}
main().catch((e) => { console.error(e); process.exit(1); });
